  1â†’use std::collections::{BTreeMap, HashMap};
  2â†’use std::fs::File;
  3â†’use std::io::{BufRead, BufReader};
  4â†’use std::path::PathBuf;
  5â†’
  6â†’use clap::Parser;
  7â†’
  8â†’use ccs_viewer::types::Record;
  9â†’
 10â†’#[derive(Parser)]
 11â†’#[command(version, about = "Claude Code session JSONL viewer")]
 12â†’struct Cli {
 13â†’    /// File or directory glob patterns to process
 14â†’    #[arg(required = true)]
 15â†’    patterns: Vec<String>,
 16â†’
 17â†’    /// Show per-file summary lines
 18â†’    #[arg(short, long)]
 19â†’    list: bool,
 20â†’
 21â†’    /// Show grouped error details
 22â†’    #[arg(short, long)]
 23â†’    errors: bool,
 24â†’
 25â†’    /// Recursively search directories for matching files
 26â†’    #[arg(short, long)]
 27â†’    recursive: bool,
 28â†’
 29â†’    /// File glob pattern for recursive mode (repeatable, default: *.jsonl)
 30â†’    #[arg(long = "glob")]
 31â†’    globs: Vec<String>,
 32â†’}
 33â†’
 34â†’/// Resolve CLI patterns into a list of file paths.
 35â†’fn resolve_files(cli: &Cli) -> Vec<PathBuf> {
 36â†’    let mut files = Vec::new();
 37â†’
 38â†’    if cli.recursive {
 39â†’        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 40â†’            vec!["*.jsonl"]
 41â†’        } else {
 42â†’            cli.globs.iter().map(|s| s.as_str()).collect()
 43â†’        };
 44â†’
 45â†’        // Expand positional patterns as directory globs.
 46â†’        for pattern in &cli.patterns {
 47â†’            let dirs: Vec<PathBuf> = match glob::glob(pattern) {
 48â†’                Ok(paths) => paths
 49â†’                    .filter_map(|p| p.ok())
 50â†’                    .filter(|p| p.is_dir())
 51â†’                    .collect(),
 52â†’                Err(e) => {
 53â†’                    eprintln!("Bad pattern {pattern:?}: {e}");
 54â†’                    std::process::exit(1);
 55â†’                }
 56â†’            };
 57â†’            if dirs.is_empty() {
 58â†’                eprintln!("No directories match {pattern:?}");
 59â†’                std::process::exit(1);
 60â†’            }
 61â†’            for dir in &dirs {
 62â†’                for fg in &file_globs {
 63â†’                    let full = format!("{}/**/{fg}", dir.display());
 64â†’                    match glob::glob(&full) {
 65â†’                        Ok(paths) => {
 66â†’                            for entry in paths.flatten() {
 67â†’                                if entry.is_file() {
 68â†’                                    files.push(entry);
 69â†’                                }
 70â†’                            }
 71â†’                        }
 72â†’                        Err(e) => {
 73â†’                            eprintln!("Bad glob {full:?}: {e}");
 74â†’                            std::process::exit(1);
 75â†’                        }
 76â†’                    }
 77â†’                }
 78â†’            }
 79â†’        }
 80â†’    } else {
 81â†’        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 82â†’            vec!["*.jsonl"]
 83â†’        } else {
 84â†’            cli.globs.iter().map(|s| s.as_str()).collect()
 85â†’        };
 86â†’
 87â†’        for pattern in &cli.patterns {
 88â†’            // Check if pattern is a literal directory path first.
 89â†’            let path = PathBuf::from(pattern);
 90â†’            if path.is_dir() {
 91â†’                // Directory: expand file globs inside it (non-recursive).
 92â†’                for fg in &file_globs {
 93â†’                    let full = format!("{}/{fg}", path.display());
 94â†’                    match glob::glob(&full) {
 95â†’                        Ok(paths) => {
 96â†’                            for entry in paths.flatten() {
 97â†’                                if entry.is_file() {
 98â†’                                    files.push(entry);
 99â†’                                }
100â†’                            }
101â†’                        }
102â†’                        Err(e) => {
103â†’                            eprintln!("Bad glob {full:?}: {e}");
104â†’                            std::process::exit(1);
105â†’                        }
106â†’                    }
107â†’                }
108â†’            } else {
109â†’                // Treat as file glob pattern.
110â†’                match glob::glob(pattern) {
111â†’                    Ok(paths) => {
112â†’                        let mut matched = Vec::new();
113â†’                        for entry in paths.flatten() {
114â†’                            if entry.is_file() {
115â†’                                matched.push(entry);
116â†’                            } else if entry.is_dir() {
117â†’                                // Glob matched a directory: expand file
118â†’                                // globs inside it (non-recursive).
119â†’                                for fg in &file_globs {
120â†’                                    let full = format!("{}/{fg}", entry.display());
121â†’                                    if let Ok(inner) = glob::glob(&full) {
122â†’                                        for f in inner.flatten() {
123â†’                                            if f.is_file() {
124â†’                                                matched.push(f);
125â†’                                            }
126â†’                                        }
127â†’                                    }
128â†’                                }
129â†’                            }
130â†’                        }
131â†’                        if matched.is_empty() {
132â†’                            eprintln!("No files match {pattern:?}");
133â†’                            std::process::exit(1);
134â†’                        }
135â†’                        files.extend(matched);
136â†’                    }
137â†’                    Err(e) => {
138â†’                        eprintln!("Bad pattern {pattern:?}: {e}");
139â†’                        std::process::exit(1);
140â†’                    }
141â†’                }
142â†’            }
143â†’        }
144â†’    }
145â†’
146â†’    files.sort();
147â†’    files.dedup();
148â†’    files
149â†’}
150â†’
151â†’/// Key for grouping errors: the serde error message + record type.
152â†’#[derive(Hash, Eq, PartialEq)]
153â†’struct ErrorKey {
154â†’    message: String,
155â†’    record_type: String,
156â†’}
157â†’
158â†’/// Tracks one group of identical errors across files.
159â†’struct ErrorGroup {
160â†’    count: usize,
161â†’    /// One representative file:line for grabbing test data.
162â†’    example_file: String,
163â†’    example_line: usize,
164â†’    /// How many distinct files contain this error.
165â†’    file_count: usize,
166â†’    /// Track which files we've seen (by index) to count distinct files.
167â†’    seen_files: Vec<usize>,
168â†’}
169â†’
170â†’fn main() {
171â†’    let cli = Cli::parse();
172â†’    let files = resolve_files(&cli);
173â†’
174â†’    if files.is_empty() {
175â†’        eprintln!("No files to process");
176â†’        std::process::exit(1);
177â†’    }
178â†’
179â†’    let mut total_records: usize = 0;
180â†’    let mut total_errors: usize = 0;
181â†’    let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();
182â†’
183â†’    for (file_idx, path) in files.iter().enumerate() {
184â†’        let file = File::open(path).unwrap_or_else(|e| {
185â†’            eprintln!("Error opening {}: {e}", path.display());
186â†’            std::process::exit(1);
187â†’        });
188â†’
189â†’        let reader = BufReader::new(file);
190â†’        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
191â†’        let mut file_errors: usize = 0;
192â†’        let filename = path
193â†’            .file_name()
194â†’            .map(|f| f.to_string_lossy().into_owned())
195â†’            .unwrap_or_else(|| path.display().to_string());
196â†’
197â†’        for (i, line) in reader.lines().enumerate() {
198â†’            let line = line.unwrap_or_else(|e| {
199â†’                eprintln!("Error reading line {}: {e}", i + 1);
200â†’                std::process::exit(1);
201â†’            });
202â†’            if line.trim().is_empty() {
203â†’                continue;
204â†’            }
205â†’            match serde_json::from_str::<Record>(&line) {
206â†’                Ok(record) => {
207â†’                    *counts.entry(record.label()).or_insert(0) += 1;
208â†’                }
209â†’                Err(e) => {
210â†’                    file_errors += 1;
211â†’                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
212â†’                        .ok()
213â†’                        .and_then(|v| v.get("type")?.as_str().map(String::from))
214â†’                        .unwrap_or_else(|| "unknown".to_string());
215â†’
216â†’                    let key = ErrorKey {
217â†’                        message: format!("{e}"),
218â†’                        record_type,
219â†’                    };
220â†’                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
221â†’                        count: 0,
222â†’                        example_file: filename.clone(),
223â†’                        example_line: i + 1,
224â†’                        file_count: 0,
225â†’                        seen_files: Vec::new(),
226â†’                    });
227â†’                    group.count += 1;
228â†’                    if !group.seen_files.contains(&file_idx) {
229â†’                        group.seen_files.push(file_idx);
230â†’                        group.file_count += 1;
231â†’                    }
232â†’                }
233â†’            }
234â†’        }
235â†’
236â†’        let file_total: usize = counts.values().sum();
237â†’        total_records += file_total;
238â†’        total_errors += file_errors;
239â†’
240â†’        if cli.list {
241â†’            let mut parts = vec![
242â†’                format!("errors: {file_errors}"),
243â†’                format!("records: {file_total}"),
244â†’            ];
245â†’            for (label, count) in &counts {
246â†’                parts.push(format!("{label}: {count}"));
247â†’            }
248â†’            println!("{filename}: {}", parts.join(", "));
249â†’        }
250â†’    }
251â†’
252â†’    let file_count = files.len();
253â†’    println!(
254â†’        "{}Summary: {file_count} file(s), {total_records} records, {total_errors} errors",
255â†’        if cli.list { "\n" } else { "" }
256â†’    );
257â†’
258â†’    if cli.errors && !error_groups.is_empty() {
259â†’        println!("\nErrors:");
260â†’        let mut groups: Vec<_> = error_groups.into_iter().collect();
261â†’        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
262â†’        for (key, group) in &groups {
263â†’            println!(
264â†’                "  {}x {} in {} ({}:{} in {} file(s))",
265â†’                group.count,
266â†’                key.message,
267â†’                key.record_type,
268â†’                group.example_file,
269â†’                group.example_line,
270â†’                group.file_count,
271â†’            );
272â†’        }
273â†’    }
274â†’
275â†’    if total_errors > 0 {
276â†’        std::process::exit(1);
277â†’    }
278â†’}
